import React, { useState } from "react";
import { Cog6ToothIcon, BellIcon, ShieldCheckIcon, CpuChipIcon } from "@heroicons/react/24/outline";
import toast from "react-hot-toast";
const tabs = [{id:"general",label:"General",icon:Cog6ToothIcon},{id:"ai",label:"AI Config",icon:CpuChipIcon},{id:"notifications",label:"Notifications",icon:BellIcon},{id:"security",label:"Security",icon:ShieldCheckIcon}];
export default function Settings() {
  const [activeTab, setActiveTab] = useState("general");
  const save = () => toast.success("Settings saved");
  return (
    <div className="space-y-5 animate-in">
      <h1 className="page-title">Settings</h1>
      <div className="flex gap-1 bg-slate-100 rounded-xl p-1 w-fit">{tabs.map(t => (<button key={t.id} onClick={() => setActiveTab(t.id)} className={`flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-medium transition-all ${activeTab===t.id?"bg-white text-slate-900 shadow-sm":"text-slate-500 hover:text-slate-700"}`}><t.icon className="w-4 h-4" />{t.label}</button>))}</div>
      <div className="card max-w-2xl">
        {activeTab==="general"&&<div className="space-y-4"><h2 className="section-title">Company Settings</h2>{[["Company Name","text","Acme Corp"],["Currency","text","INR"],["Working Days/Month","number","26"]].map(([l,t,p])=>(<div key={l}><label className="label">{l}</label><input type={t} className="input" placeholder={p} defaultValue={p} /></div>))}<button onClick={save} className="btn-primary">Save Changes</button></div>}
        {activeTab==="ai"&&<div className="space-y-4"><h2 className="section-title">AI Configuration</h2><div><label className="label">OpenAI API Key</label><input type="password" className="input" placeholder="sk-••••••••••" /></div><button onClick={save} className="btn-primary">Save AI Settings</button></div>}
        {activeTab==="notifications"&&<div className="space-y-4"><h2 className="section-title">Notifications</h2>{[["Leave Approval","Get notified on leave decisions"],["Payroll Release","Notify when payslips are ready"],["Attrition Alert","AI-detected high-risk employees"]].map(([l,d])=>(<label key={l} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100"><div><p className="text-sm font-medium text-slate-800">{l}</p><p className="text-xs text-slate-500">{d}</p></div><input type="checkbox" defaultChecked className="w-4 h-4 accent-primary-600" /></label>))}<button onClick={save} className="btn-primary">Save Notifications</button></div>}
        {activeTab==="security"&&<div className="space-y-4"><h2 className="section-title">Change Password</h2><div><label className="label">Current Password</label><input type="password" className="input" /></div><div><label className="label">New Password</label><input type="password" className="input" /></div><button onClick={save} className="btn-primary">Update Password</button></div>}
      </div>
    </div>
  );
}
